    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_Always_EndsWith2DecimalPlaces()
    {
        var result = _formatter.FormatCurrency(5m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_MatchesExpectedPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

